//vip.opstream10.com/20220420/9239_d7880e61/index.m3u8"}]}],"time":"60 Phút / Tập","description":"<p>Gần 100 năm sau khi một thảm họa hạt nhân giết chết mọi sinh vật tồn tại trên Trái Đất. Một bộ phận loài người thoát nạn và đã sống bên ngoài vũ trụ được 3 thế hệ. Khi nguồn tài nguyên, lương thực, không khí ngày một cạn kiệt, họ quyết định đưa 100 tội phạm thiếu niên xuống Trái Đất để thử nghiệm xem liệu điều kiện và môi trường ở đó có phù hợp cho loài người quay trở lại sinh sống hay chưa. Ở Trái Đất, họ phải đối mặt với những con quái thú, những loài thực vật kỳ lạ do chịu ảnh hưởng của phóng xạ. Chuyện ngày càng rắc rối khi 100 thiếu niên này quyết định nổi loạn và không cam chịu sự theo dõi của những người đứng đầu. Mọi chuyện sẽ diễn biến thế nào khi vận mệnh của loài người đang nằm trên bờ vực nguy hiểm?</p>","tmdb":{"type":"tv","id":"48866","season":5,"vote_average":7.888,"vote_count":8414},"modified":"2023-07-02T16:53:21.000Z","_image_preserved":true},{"id":"626114f1db43524328b0020d","_id":"626114f1db43524328b0020d","title":"Hoa Cỏ Lau Trong Bão","origin_name":"Grass Flower In The Storm","slug":"hoa-co-lau-trong-bao","year":2018,"type":"series","genre":[{"id":"620a220de0fc277084dfd16d","name":"Tình Cảm","slug":"tinh-cam"},{"id":"620a2238e0fc277084dfd291","name":"Tâm Lý","slug":"tam-ly"}],"country":[{"id":"620a2318e0fc277084dfd77a","name":"Thái Lan","slug":"thai-lan"}],"lang_key":"Vietsub","episode_current":"Hoàn Tất (32/32)","quality":"HD","is_4k":false,"is_exclusive":false,"status":"completed","showtimes":"","chieurap":false,"sub_docquyen":false,"episodes":[{"is_ai":false,"server_name":"Vietsub #1","server_data":[{"name":"1","slug":"1","filename":"hoa-co-lau-trong-bao-grass-flower-in-the-storm-tap-1","link_embed":"https://vip.opstream10.com/share/c617ea9609ec341360765f6d29b5814e","link_m3u8":"https://vip.opstream10.com/20220420/9238_2f3fc319/index.m3u8"},{"name":"2","slug":"2","filename":"hoa-co-lau-trong-bao-grass-flower-in-the-storm-tap-2","link_embed":"h